    const filePath = path.join(migrationsDir, file);
    let sql = fs.readFileSync(filePath, "utf-8");

    // Inject explicit FK validation after schema changes and before re-enabling
    // Replace the final "PRAGMA foreign_keys=ON;" with a validation sequence
    sql = sql.replace(
      /PRAGMA foreign_keys=ON;/,
      `PRAGMA foreign_keys=ON;
PRAGMA integrity_check;` // Validates but does not auto-cascade
    );

