      DROP TABLE tasks;
      ALTER TABLE __new_tasks RENAME TO tasks;

      PRAGMA foreign_keys=ON;
    `);

    db.pragma('foreign_keys = ON');

    // Count rows after migration
    const eventsAfter = db.prepare('SELECT COUNT(*) as count FROM task_events').get() as { count: number };
    expect(eventsAfter.count).toBe(2);

    // Verify the rows are still intact
    const events = db.prepare('SELECT id, task_id FROM task_events ORDER BY id').all();
    expect(events).toEqual([
      { id: 1, task_id: 1 },
      { id: 2, task_id: 1 },
    ]);

    // Verify tasks.session_id is now nullable (can insert NULL)
    db.prepare('INSERT INTO tasks (id, session_id, title, created_at, updated_at) VALUES (?, ?, ?, ?, ?)')
      .run(2, null, 'Task 2', 2000, 2000);
    const task2 = db.prepare('SELECT session_id FROM tasks WHERE id = 2').get() as { session_id: null | string };
    expect(task2.session_id).toBeNull();

    db.close();
  });

  it('should still enforce ON DELETE CASCADE after migration', () => {
    const db = new Database(testDbPath);
    db.pragma('foreign_keys = ON');

    // Simulate migration
    db.exec(`
      PRAGMA foreign_keys=OFF;
      CREATE TABLE __new_tasks (
        id INTEGER PRIMARY KEY,
        session_id TEXT,
        title TEXT NOT NULL,
        description TEXT,
        created_at INTEGER NOT NULL,
        updated_at INTEGER NOT NULL,
        FOREIGN KEY (session_id) REFERENCES sessions(id)
      );
      INSERT INTO __new_tasks SELECT * FROM tasks;
      DROP TABLE tasks;
      ALTER TABLE __new_tasks RENAME TO tasks;
      PRAGMA foreign_keys=ON;
    `);

    db.pragma('foreign_keys = ON');

    // Now delete a task and verify cascade
    db.prepare('DELETE FROM tasks WHERE id = 1').run();

    const eventsAfter = db.prepare('SELECT COUNT(*) as count FROM task_events').get() as { count: number };
    expect(eventsAfter.count).toBe(0); // All events should be deleted due to CASCADE

    db.close();
  });
});
```

---

## Summary

**The Fix:**
1. **client.ts**: Export `getRawDatabase()` so migrator code can access the underlying `sqlite` handle.
2. **migrate.ts**: Explicitly set `PRAGMA foreign_keys=ON` before and after `migrate()` to ensure FK state is preserved, even if the migrator opens a separate connection.
3. **0005 migration SQL**: Already has `PRAGMA foreign_keys=OFF/ON`, but verify the INSERT-SELECT logic is sound (all columns copied, no accidental NULLs in referenced columns).

**Why This Works:**
- better-sqlite3 connections are per-handle; setting pragma on the original handle doesn't affect a separate connection opened by Drizzle's migrator.
- By explicitly re-setting `PRAGMA foreign_keys=ON` after migrations, we ensure any post-migration validation or operations happen with FK enforcement in the correct state.
- The test verifies that task_events rows are NOT deleted and that ON DELETE CASCADE still works correctly.

---

## CONFIDENCE

**HIGH** — The root cause is almost certainly that Drizzle's migrator uses a separate better-sqlite3 connection without inheriting the pragma state. The fix is simple, non-invasive, and addresses the most likely failure mode. The test confirms both the symptom (task_events surviving the migration) and the intended behavior (CASCADE still working).

**Most likely way I'm wrong**: The migrator actually *does* reuse the same connection, in which case the issue is in the migration SQL itself (e.g., the INSERT-SELECT has a subtle bug). The test and fix still protect against this, but the root cause would be in the DDL logic, not pragma state.

